    def get_option_history(self, name: str) -> list[dict[str, t.Any]] | None:
        """Return the recorded history of values for the option ``name``.

        ``name`` can either be the parameter's name (e.g. ``"count"``)
        or one of its option flags (e.g. ``"--count"`` or ``"-c"``),
        which is resolved to the parameter's name using this context's
        command.

        Returns ``None`` if history tracking was not enabled for this
        context (see the ``track_changes`` parameter on
        :class:`Command`). Returns an empty list if tracking is enabled
        but the option has no recorded history, including when the
        option does not exist.

        :param name: The parameter name or an option flag.

        .. versionadded:: 8.3
        """
        if not self._track_changes:
            return None

        if name.startswith("-"):
            resolved_name = None

            for param in self.command.get_params(self):
                if name in param.opts or name in param.secondary_opts:
                    resolved_name = param.name
                    break

            if resolved_name is None:
                return []

            name = resolved_name

        return self._option_history.get(name, [])


